class Solution {
    public int magicalString(int n) {
        int[] magical = new int[n];
        magical[0] = 1;
        magical[1] = 2;
        int head = 2, tail = 2;
        while (tail < n) {
            int count = magical[head];
            int num = 3 - magical[tail - 1];
            while (tail < n && count > 0) {
                magical[tail] = num;
                tail++;
                count--;
            }
            head++;
        }
        int countOnes = 0;
        for (int i = 0; i < n; i++) {
            if (magical[i] == 1) {
                countOnes++;
            }
        }
        return countOnes;
    }
}
